INSERT INTO public.challenges (name, slug, description, start_date, end_date, category)
VALUES (
  '1-2-3-4 Strength Challenge',
  '1234-strength-challenge',
  E'Die 1-2-3-4 Challenge ist Powerlifting für normale Menschen!\nDie 1-2-3-4 beziehen sich auf die Anzahl der Scheiben auf der Langhantel, die für verschiedene Übungen erreicht werden müssen.\nWir arbeiten mit 4 Lifts:\nPress, Bench Press, Squat, Deadlift.\nFrauen machen die Presses mit je 10kg pro Seite, mit 2× 10kg pro Seite für das Bankdrücken, und entsprechend 3 bzw. 4 10er Scheiben pro Seite für Squats und Deadlifts.\nFür Männer gilt dasselbe Prinzip, aber mit 20kg Scheiben.\n\nBeginner können die Challenge auch auf sich nehmen: für Frauen gilt die Abfolge hier mit 5er Scheiben, für Männer mit 15kg Scheiben.\n\n📋 Standard Frauen: Press 40kg · Bench 60kg · Squat 80kg · Deadlift 100kg\n📋 Standard Männer: Press 60kg · Bench 100kg · Squat 140kg · Deadlift 180kg\n📋 Beginner Frauen: Press 30kg · Bench 40kg · Squat 50kg · Deadlift 60kg\n📋 Beginner Männer: Press 50kg · Bench 80kg · Squat 110kg · Deadlift 140kg\n\nDie 1-2-3-4 Challenge ist eine sinnvolle, ehrgeizige, aber machbare Challenge, mit der man sich herausfordern und auf die man hin trainieren kann.\n\nWer die Standard-Version meistert, darf sich mit Fug und Recht "Strong Enough!" nennen!\nEnjoy the Ride!',
  '2026-01-01',
  NULL,
  'gym'
);